_REQUIRE_DECODING_CACHE_MAX_SIZE = 10_000
_require_decoding_cache: Dict[Tuple[int, bool], Tuple[FeatureType, bool]] = {}


def require_decoding(feature: FeatureType, ignore_decode_attribute: bool = False) -> bool:
    """Check if a (possibly nested) feature requires decoding.

    Args:
        feature (FeatureType): the feature type to be checked
        ignore_decode_attribute (:obj:`bool`, default ``False``): Whether to ignore the current value
            of the `decode` attribute of the decodable feature types.
    Returns:
        :obj:`bool`
    """
    cache_key = (id(feature), ignore_decode_attribute)
    cache_entry = _require_decoding_cache.get(cache_key)
    if cache_entry is not None and cache_entry[0] is feature:
        return cache_entry[1]
    if isinstance(feature, dict):
        result = any(require_decoding(f) for f in feature.values())
    elif isinstance(feature, (list, tuple)):
        result = require_decoding(feature[0])
    elif isinstance(feature, Sequence):
        result = require_decoding(feature.feature)
    else:
        result = hasattr(feature, "decode_example") and (feature.decode if not ignore_decode_attribute else True)
    if len(_require_decoding_cache) >= _REQUIRE_DECODING_CACHE_MAX_SIZE:
        _require_decoding_cache.clear()
    _require_decoding_cache[cache_key] = (feature, result)
    return result


def keep_features_dicts_synced(func):
    """
    Wrapper to keep the secondary dictionary, which tracks whether keys are decodable, of the :class:`datasets.Features` object
    in sync with the main dictionary.
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
            args = args[1:]
        else:
            self: "Features" = kwargs.pop("self")
        out = func(self, *args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper._decorator_name_ = "_keep_dicts_synced"
    return wrapper


